package com.exam.service;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.core.metadata.IPage;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import com.exam.dto.ExamCreateRequest;
import com.exam.dto.ExamListResponse;
import com.exam.dto.ExamUpdateRequest;
import com.exam.entity.*;
import com.exam.enums.ExamStatus;
import com.exam.enums.RecordStatus;
import com.exam.exception.BizException;
import com.exam.exception.ErrorCode;
import com.exam.mapper.*;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.LocalDateTime;
import java.util.*;
import java.util.concurrent.ThreadLocalRandom;

/**
 * 试卷服务
 */
@Slf4j
@Service
public class ExamService {

    private final ExamMapper examMapper;
    private final QuestionBankMapper questionBankMapper;
    private final SysUserMapper sysUserMapper;
    private final ExamRecordMapper examRecordMapper;
    private final ExamRecordQuestionMapper examRecordQuestionMapper;
    private final AnswerDetailMapper answerDetailMapper;

    public ExamService(ExamMapper examMapper, QuestionBankMapper questionBankMapper,
                       SysUserMapper sysUserMapper, ExamRecordMapper examRecordMapper,
                       ExamRecordQuestionMapper examRecordQuestionMapper,
                       AnswerDetailMapper answerDetailMapper) {
        this.examMapper = examMapper;
        this.questionBankMapper = questionBankMapper;
        this.sysUserMapper = sysUserMapper;
        this.examRecordMapper = examRecordMapper;
        this.examRecordQuestionMapper = examRecordQuestionMapper;
        this.answerDetailMapper = answerDetailMapper;
    }

    /**
     * 分页查询试卷列表（含答卷人数）
     */
    public IPage<ExamListResponse> listExams(int page, int size) {
        return examMapper.selectExamListWithCount(new Page<>(page, size));
    }

    /**
     * 创建试卷（初始状态为草稿）
     */
    public Exam create(ExamCreateRequest req, Long userId) {
        Exam exam = Exam.builder()
                .title(req.getTitle())
                .timeLimitMin(req.getTimeLimitMin())
                .showAnswer(req.getShowAnswer())
                .showAnalysis(req.getShowAnalysis())
                .questionCount(req.getQuestionCount())
                .maxAttempts(req.getMaxAttempts())
                .accessMode(req.getAccessMode())
                .status(ExamStatus.DRAFT)
                .createdBy(userId)
                .build();
        examMapper.insert(exam);
        log.info("[lbl][Exam][CREATE] 创建试卷, examId={}, userId={}", exam.getId(), userId);
        return exam;
    }

    /**
     * 更新试卷（仅草稿状态可编辑）
     */
    public void update(Long id, ExamUpdateRequest req) {
        Exam exam = getExamOrThrow(id);
        if (exam.getStatus() != ExamStatus.DRAFT) {
            throw new BizException(ErrorCode.EXAM_NOT_DRAFT);
        }
        exam.setTitle(req.getTitle());
        exam.setTimeLimitMin(req.getTimeLimitMin());
        exam.setShowAnswer(req.getShowAnswer());
        exam.setShowAnalysis(req.getShowAnalysis());
        exam.setQuestionCount(req.getQuestionCount());
        exam.setMaxAttempts(req.getMaxAttempts());
        exam.setAccessMode(req.getAccessMode());
        examMapper.updateById(exam);
        log.info("[lbl][Exam][UPDATE] 更新试卷, examId={}", id);
    }

    /**
     * 删除试卷（草稿或已关闭状态可删除，已发布状态需先关闭或取消发布）
     */
    public void delete(Long id) {
        Exam exam = getExamOrThrow(id);
        if (exam.getStatus() == ExamStatus.PUBLISHED) {
            throw new BizException(ErrorCode.EXAM_NOT_DRAFT);
        }
        examMapper.deleteById(id);
        log.info("[lbl][Exam][DELETE] 删除试卷, examId={}, status={}", id, exam.getStatus());
    }

    /**
     * 发布试卷（草稿 -> 已发布，需至少有一道题目）
     */
    public void publish(Long id) {
        Exam exam = getExamOrThrow(id);
        if (exam.getStatus() != ExamStatus.DRAFT) {
            throw new BizException(ErrorCode.EXAM_NOT_DRAFT);
        }
        // 校验题目数量
        long questionCount = questionBankMapper.selectCount(
                new LambdaQueryWrapper<QuestionBank>().eq(QuestionBank::getExamId, id));
        if (questionCount == 0) {
            throw new BizException(ErrorCode.EXAM_NO_QUESTIONS);
        }
        exam.setStatus(ExamStatus.PUBLISHED);
        examMapper.updateById(exam);
        log.info("[lbl][Exam][PUBLISH] 发布试卷, examId={}, questionCount={}", id, questionCount);
    }

    /**
     * 取消发布试卷（已发布 -> 草稿）
     */
    public void unpublish(Long id) {
        Exam exam = getExamOrThrow(id);
        if (exam.getStatus() != ExamStatus.PUBLISHED) {
            throw new BizException(ErrorCode.EXAM_NOT_PUBLISHED);
        }
        exam.setStatus(ExamStatus.DRAFT);
        examMapper.updateById(exam);
        log.info("[lbl][Exam][UNPUBLISH] 取消发布试卷, examId={}", id);
    }

    /**
     * 关闭试卷（已发布 -> 已关闭）
     */
    public void close(Long id) {
        Exam exam = getExamOrThrow(id);
        if (exam.getStatus() != ExamStatus.PUBLISHED) {
            throw new BizException(ErrorCode.EXAM_NOT_PUBLISHED);
        }
        exam.setStatus(ExamStatus.CLOSED);
        examMapper.updateById(exam);
        log.info("[lbl][Exam][CLOSE] 关闭试卷, examId={}", id);
    }

    /**
     * 重新开放试卷（已关闭 -> 已发布）
     */
    public void reopen(Long id) {
        Exam exam = getExamOrThrow(id);
        if (exam.getStatus() != ExamStatus.CLOSED) {
            throw new BizException(ErrorCode.EXAM_NOT_PUBLISHED);
        }
        exam.setStatus(ExamStatus.PUBLISHED);
        examMapper.updateById(exam);
        log.info("[lbl][Exam][REOPEN] 重新开放试卷, examId={}", id);
    }

    /**
     * Mock 考试数据：批量创建模拟用户并随机答题
     *
     * @param examId    试卷ID（null 则随机选一个已发布试卷）
     * @param userCount 模拟用户数量
     * @return 生成的考试记录数
     */
    @Transactional(rollbackFor = Exception.class)
    public int mockExam(Long examId, int userCount) {
        // 1. 确定试卷
        Exam exam;
        if (examId != null) {
            exam = getExamOrThrow(examId);
        } else {
            List<Exam> publishedExams = examMapper.selectList(
                    new LambdaQueryWrapper<Exam>().eq(Exam::getStatus, ExamStatus.PUBLISHED));
            if (publishedExams.isEmpty()) {
                // 也查已关闭的试卷
                publishedExams = examMapper.selectList(
                        new LambdaQueryWrapper<Exam>().eq(Exam::getStatus, ExamStatus.CLOSED));
            }
            if (publishedExams.isEmpty()) {
                throw new BizException(ErrorCode.NOT_FOUND);
            }
            exam = publishedExams.get(ThreadLocalRandom.current().nextInt(publishedExams.size()));
        }

        // 2. 获取题目
        List<QuestionBank> questions = questionBankMapper.selectList(
                new LambdaQueryWrapper<QuestionBank>()
                        .eq(QuestionBank::getExamId, exam.getId())
                        .orderByAsc(QuestionBank::getSortOrder));
        if (questions.isEmpty()) {
            throw new BizException(ErrorCode.EXAM_NO_QUESTIONS);
        }

        // 确定每人抽题数
        int drawCount = (exam.getQuestionCount() != null && exam.getQuestionCount() > 0
                && exam.getQuestionCount() < questions.size())
                ? exam.getQuestionCount() : questions.size();

        String[] options = {"A", "B", "C", "D"};
        ThreadLocalRandom random = ThreadLocalRandom.current();
        LocalDateTime now = LocalDateTime.now();

        // 3. 批量创建用户并答题
        for (int i = 0; i < userCount; i++) {
            // 创建 mock 用户
            String mockId = "mock-" + UUID.randomUUID().toString().substring(0, 8);
            SysUser user = SysUser.builder()
                    .oaUserId(mockId)
                    .username(mockId)
                    .displayName("模拟用户" + (i + 1))
                    .isAdmin(false)
                    .build();
            sysUserMapper.insert(user);

            // 随机抽题
            List<QuestionBank> pool = new ArrayList<>(questions);
            Collections.shuffle(pool, new Random(random.nextLong()));
            List<QuestionBank> drawn = pool.subList(0, drawCount);

            // 创建考试记录
            LocalDateTime startTime = now.minusMinutes(random.nextInt(10, 60));
            LocalDateTime endTime = startTime.plusMinutes(random.nextInt(5, Math.max(6, exam.getTimeLimitMin() != null ? exam.getTimeLimitMin() : 30)));

            ExamRecord record = ExamRecord.builder()
                    .examId(exam.getId())
                    .userId(user.getId())
                    .startTime(startTime)
                    .endTime(endTime)
                    .status(RecordStatus.SUBMITTED)
                    .attemptNo(1)
                    .build();
            examRecordMapper.insert(record);

            // 插入记录-题目关联 + 答题明细 + 计分
            int correctCount = 0;
            for (int j = 0; j < drawn.size(); j++) {
                QuestionBank q = drawn.get(j);

                // 关联
                examRecordQuestionMapper.insert(ExamRecordQuestion.builder()
                        .recordId(record.getId())
                        .questionId(q.getId())
                        .sortOrder(j + 1)
                        .build());

                // 随机答题
                String userAnswer = options[random.nextInt(options.length)];
                boolean isCorrect = userAnswer.equals(q.getCorrectAnswer());
                if (isCorrect) {
                    correctCount++;
                }

                answerDetailMapper.insert(AnswerDetail.builder()
                        .recordId(record.getId())
                        .questionId(q.getId())
                        .userAnswer(userAnswer)
                        .isCorrect(isCorrect)
                        .build());
            }

            // 计算分数并更新记录
            BigDecimal score = new BigDecimal(100)
                    .multiply(new BigDecimal(correctCount))
                    .divide(new BigDecimal(drawn.size()), 2, RoundingMode.HALF_UP);
            record.setScore(score);
            examRecordMapper.updateById(record);
        }

        log.info("[lbl][Exam][MOCK] Mock考试数据, examId={}, examTitle={}, userCount={}",
                exam.getId(), exam.getTitle(), userCount);
        return userCount;
    }

    /**
     * 根据 ID 查询试卷详情（管理员用，含实时题目数量和答题人数）
     */
    public ExamListResponse getDetailWithCount(Long id) {
        ExamListResponse detail = examMapper.selectExamDetailWithCount(id);
        if (detail == null) {
            throw new BizException(ErrorCode.NOT_FOUND);
        }
        return detail;
    }

    /**
     * 更新试卷显示设置（不限状态）
     */
    public void updateSettings(Long id, Boolean showAnswer, Boolean showAnalysis) {
        Exam exam = getExamOrThrow(id);
        exam.setShowAnswer(showAnswer);
        exam.setShowAnalysis(showAnalysis);
        examMapper.updateById(exam);
        log.info("[lbl][Exam][SETTINGS] 更新试卷显示设置, examId={}, showAnswer={}, showAnalysis={}",
                id, showAnswer, showAnalysis);
    }

    /**
     * 根据 ID 查询试卷，不存在则抛 NOT_FOUND
     */
    private Exam getExamOrThrow(Long id) {
        Exam exam = examMapper.selectById(id);
        if (exam == null) {
            throw new BizException(ErrorCode.NOT_FOUND);
        }
        return exam;
    }
}

