package com.exam.exception;

import lombok.Getter;

/**
 * 错误码枚举
 */
@Getter
public enum ErrorCode {

    SUCCESS(200, "操作成功"),
    BAD_REQUEST(400, "请求参数错误"),
    UNAUTHORIZED(401, "未登录或登录已过期"),
    FORBIDDEN(403, "无权限访问"),
    NOT_FOUND(404, "资源不存在"),
    INTERNAL_ERROR(500, "系统内部错误"),

    EXAM_NOT_DRAFT(1001, "试卷非草稿状态，不可操作"),
    EXAM_NOT_PUBLISHED(1002, "试卷未发布"),
    EXAM_NO_QUESTIONS(1003, "试卷没有题目，不可发布"),
    MAX_ATTEMPTS_REACHED(1004, "已达最大考试次数"),
    EXAM_IN_PROGRESS(1005, "存在进行中的考试"),
    RECORD_NOT_FOUND(1006, "考试记录不存在"),
    RECORD_ALREADY_SUBMITTED(1007, "考试已提交"),

    TOKEN_INVALID(2001, "API Token 无效"),
    TOKEN_EXPIRED(2002, "API Token 已过期"),
    TOKEN_DISABLED(2003, "API Token 已禁用");

    private final int code;
    private final String message;

    ErrorCode(int code, String message) {
        this.code = code;
        this.message = message;
    }
}

