package com.exam.controller;

import com.exam.dto.QuestionBatchRequest;
import com.exam.dto.Result;
import com.exam.entity.ApiCallLog;
import com.exam.service.ApiTokenService;
import com.exam.service.QuestionService;
import com.fasterxml.jackson.databind.ObjectMapper;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

/**
 * 开放 API — AI 通过 API Token 调用
 */
@Slf4j
@RestController
@RequestMapping("/api/open")
@RequiredArgsConstructor
public class OpenApiController {

    private final QuestionService questionService;
    private final ApiTokenService apiTokenService;
    private final ObjectMapper objectMapper;

    /**
     * 批量新增题目（复用已有逻辑）
     */
    @PostMapping("/exams/{examId}/questions/batch")
    public Result<Integer> batchCreate(@PathVariable Long examId,
                                       @Valid @RequestBody QuestionBatchRequest req,
                                       Authentication auth,
                                       HttpServletRequest httpRequest) {
        long startTime = System.currentTimeMillis();
        // credentials 中存放了 tokenId（在 Filter 中设置）
        Long tokenId = (Long) auth.getCredentials();
        int count = req.getQuestions() != null ? req.getQuestions().size() : 0;
        log.info("[lbl][OpenAPI][BATCH_CREATE] 批量导入题目请求, examId={}, count={}, tokenId={}",
                examId, count, tokenId);

        Result<Integer> result;
        int responseCode = 0;
        String responseBody = null;
        try {
            int created = questionService.batchCreate(examId, req);
            result = Result.ok(created);
            responseCode = 200;
            responseBody = String.valueOf(created);
        } catch (Exception e) {
            responseCode = 500;
            responseBody = e.getMessage();
            throw e;
        } finally {
            // 记录调用日志
            long duration = System.currentTimeMillis() - startTime;
            try {
                String reqBodySummary = count + " questions for exam " + examId;
                apiTokenService.logCall(ApiCallLog.builder()
                        .tokenId(tokenId)
                        .requestPath(httpRequest.getRequestURI())
                        .requestMethod(httpRequest.getMethod())
                        .requestBody(reqBodySummary)
                        .responseCode(responseCode)
                        .responseBody(responseBody)
                        .durationMs((int) duration)
                        .clientIp(getClientIp(httpRequest))
                        .build());
            } catch (Exception logEx) {
                log.warn("[lbl][OpenAPI][LOG] 记录调用日志失败, tokenId={}, error={}", tokenId, logEx.getMessage());
            }
        }
        return result;
    }

    private String getClientIp(HttpServletRequest request) {
        String ip = request.getHeader("X-Forwarded-For");
        if (ip != null && !ip.isEmpty() && !"unknown".equalsIgnoreCase(ip)) {
            return ip.split(",")[0].trim();
        }
        ip = request.getHeader("X-Real-IP");
        if (ip != null && !ip.isEmpty() && !"unknown".equalsIgnoreCase(ip)) {
            return ip;
        }
        return request.getRemoteAddr();
    }
}

