  2→
  3→import com.exam.entity.ApiToken;
  4→import com.exam.service.ApiTokenService;
  5→import com.exam.util.JwtUtil;
  6→import jakarta.servlet.FilterChain;
  7→import jakarta.servlet.ServletException;
  8→import jakarta.servlet.http.HttpServletRequest;
  9→import jakarta.servlet.http.HttpServletResponse;
 10→import lombok.RequiredArgsConstructor;
 11→import lombok.extern.slf4j.Slf4j;
 12→import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
 13→import org.springframework.security.core.authority.SimpleGrantedAuthority;
 14→import org.springframework.security.core.context.SecurityContextHolder;
 15→import org.springframework.stereotype.Component;
 16→import org.springframework.util.AntPathMatcher;
 17→import org.springframework.util.StringUtils;
 18→import org.springframework.web.filter.OncePerRequestFilter;
 19→
 20→import java.io.IOException;
 21→import java.util.ArrayList;
 22→import java.util.List;
 23→
 24→/**
 25→ * JWT 认证过滤器：从 Authorization header 解析 token 并设置认证信息
 26→ */
 27→@Slf4j
 28→@Component
 29→@RequiredArgsConstructor
 30→public class JwtAuthenticationFilter extends OncePerRequestFilter {
 31→
 32→    private static final String BEARER_PREFIX = "Bearer ";
 33→    private static final String API_TOKEN_HEADER = "X-API-Token";
 34→    private static final AntPathMatcher PATH_MATCHER = new AntPathMatcher();
 35→
 36→    /** 白名单路径，直接放行不解析 token */
 37→    private static final List<String> WHITE_LIST = List.of("/api/auth/oauth2/**");
 38→
 39→    /** 开放 API 路径，走 API Token 认证 */
 40→    private static final String OPEN_API_PATTERN = "/api/open/**";
 41→
 42→    private final JwtUtil jwtUtil;
 43→    private final ApiTokenService apiTokenService;
 44→
 45→    @Override
 46→    protected void doFilterInternal(HttpServletRequest request,
 47→                                    HttpServletResponse response,
 48→                                    FilterChain filterChain) throws ServletException, IOException {
 49→        String path = request.getRequestURI();
 50→
 51→        // 白名单路径直接放行
 52→        boolean isWhiteListed = WHITE_LIST.stream()
 53→                .anyMatch(pattern -> PATH_MATCHER.match(pattern, path));
 54→        if (isWhiteListed) {
 55→            filterChain.doFilter(request, response);
 56→            return;
 57→        }
 58→
 59→        // 开放 API 路径：优先走 X-API-Token 认证
 60→        if (PATH_MATCHER.match(OPEN_API_PATTERN, path)) {
 61→            String apiTokenValue = request.getHeader(API_TOKEN_HEADER);
 62→            if (StringUtils.hasText(apiTokenValue)) {
 63→                try {
 64→                    ApiToken apiToken = apiTokenService.validate(apiTokenValue);
 65→                    // 以 token 创建者身份设置认证，赋予 ADMIN 权限以调用题目接口
 66→                    List<SimpleGrantedAuthority> authorities = List.of(
 67→                            new SimpleGrantedAuthority("ROLE_ADMIN"),
 68→                            new SimpleGrantedAuthority("ROLE_USER"));
 69→                    UsernamePasswordAuthenticationToken authentication =
 70→                            new UsernamePasswordAuthenticationToken(apiToken.getCreatedBy(), apiToken.getId(), authorities);
 71→                    SecurityContextHolder.getContext().setAuthentication(authentication);
 72→                } catch (Exception e) {
 73→                    log.warn("[lbl][Auth][API-Token] 验证失败, path={}, error={}", path, e.getMessage());
 74→                }
 75→                filterChain.doFilter(request, response);
 76→                return;
 77→            }
 78→        }
 79→
 80→        // 解析 Authorization header（JWT）
 81→        String authHeader = request.getHeader("Authorization");
 82→        if (StringUtils.hasText(authHeader) && authHeader.startsWith(BEARER_PREFIX)) {
 83→            String token = authHeader.substring(BEARER_PREFIX.length());
 84→            try {
 85→                Long userId = jwtUtil.getUserId(token);
 86→                Boolean isAdmin = jwtUtil.getIsAdmin(token);
 87→
 88→                List<SimpleGrantedAuthority> authorities = new ArrayList<>();
 89→                if (Boolean.TRUE.equals(isAdmin)) {
 90→                    authorities.add(new SimpleGrantedAuthority("ROLE_ADMIN"));
 91→                }
 92→                authorities.add(new SimpleGrantedAuthority("ROLE_USER"));
 93→
 94→                UsernamePasswordAuthenticationToken authentication =
 95→                        new UsernamePasswordAuthenticationToken(userId, null, authorities);
